body.script:
(function() {
    if (typeof jQuery !== 'undefined') {
        jQuery(document).ready(function($) {
            // Function to replace currency symbols
            function replaceCurrency() {
                // Target form 4527 specifically
                $('#wpforms-4527').find('.wpforms-field-payment, .wpforms-payment-total, .wpforms-field-label, .wpforms-field-sublabel, .wpforms-field-description, input, select, option').each(function() {
                    // Replace in HTML content
                    var html = $(this).html();
                    if (html && html.indexOf('£') !== -1) {
                        $(this).html(html.replace(/£/g, '₱'));
                    }

                    // Replace in value attribute
                    var val = $(this).val();
                    if (val && val.indexOf('£') !== -1) {
                        $(this).val(val.replace(/£/g, '₱'));
                    }

                    // Replace in text content
                    var text = $(this).text();
                    if (text && text.indexOf('£') !== -1) {
                        $(this).text(text.replace(/£/g, '₱'));
                    }
                });
            }

            // Run immediately
            replaceCurrency();

            // Run on any form change
            $('#wpforms-4527').on('change input', function() {
                setTimeout(replaceCurrency, 100);
            });

            // Keep checking (for dynamic updates)
            setInterval(replaceCurrency, 1000);
        });
    }
})();

const lazyloadRunObserver = () => {
	const lazyloadBackgrounds = document.querySelectorAll( `.e-con.e-parent:not(.e-lazyloaded)` );
	const lazyloadBackgroundObserver = new IntersectionObserver( ( entries ) => {
		entries.forEach( ( entry ) => {
			if ( entry.isIntersecting ) {
				let lazyloadBackground = entry.target;
				if( lazyloadBackground ) {
					lazyloadBackground.classList.add( 'e-lazyloaded' );
				}
				lazyloadBackgroundObserver.unobserve( entry.target );
			}
		});
	}, { rootMargin: '200px 0px 200px 0px' } );
	lazyloadBackgrounds.forEach( ( lazyloadBackground ) => {
		lazyloadBackgroundObserver.observe( lazyloadBackground );
	} );
};
const events = [
	'DOMContentLoaded',
	'elementor/lazyload/observe',
];
events.forEach( ( event ) => {
	document.addEventListener( event, lazyloadRunObserver );
} );

