jQuery(document).ready(function() {
		var initialValue = jQuery('input[name="wpforms[fields][25]"]').val();
    if(initialValue == '1') {
        jQuery('input[name="wpforms[fields][28]"]')[0].click();
    }
    jQuery(document).on('change', 'input[name="wpforms[fields][25]"]', function() {
        var number_of_people = jQuery(this).val(); 
        jQuery('input[name="wpforms[fields][28]"]').prop('checked', false); 
        jQuery('input[name="wpforms[fields][28]"]')[number_of_people - 1].click();
    });
});
